## ============================================================================
## External Libraries Integration
## AUTO-GENERATED by nimble discover - DO NOT EDIT
## ============================================================================

import std/strutils
import ../core/types
import discovery

## Conditional imports for each installed library

when defined(harding_mysql):
  import mysql/src/mysql/mysql

when defined(harding_bitbarrel):
  import bitbarrel/src/bitbarrel/bitbarrel

## ============================================================================
## Library Installation
## ============================================================================

proc installExternalLibraries*(interp: var Interpreter) =
  ## Install all discovered and enabled external libraries.
  ##
  ## This proc is called by loadStdlib after the standard library is loaded.
  ## Each library is conditionally compiled based on whether it's installed
  ## and enabled via compile flags.

  let installedLibs = discoverInstalledLibraries()
  discard installedLibs

  debug("Installing external libraries...")

  ## mysql (1.0.0)
  when defined(harding_mysql):
    try:
      installMysql(interp)
      debug("External library installed: mysql")
    except:
      warn("Failed to install library: mysql")
  else:
    debug("Library mysql not enabled at compile time")

  ## bitbarrel (0.1.0)
  when defined(harding_bitbarrel):
    try:
      installBitbarrel(interp)
      debug("External library installed: bitbarrel")
    except:
      warn("Failed to install library: bitbarrel")
  else:
    debug("Library bitbarrel not enabled at compile time")

  debug("External library installation complete")

## ============================================================================
## Compile Flags Generation
## ============================================================================

proc getExternalCompileFlags*(): string =
  ## Get compile flags for all installed external libraries.
  ##
  ## This is used by the build system to automatically enable
  ## all installed libraries when compiling Harding.
  var flags: seq[string] = @[]

  flags.add("-d:harding_mysql")
  flags.add("-d:harding_bitbarrel")

  return flags.join(" ")

## ============================================================================
## Built Libraries
## ============================================================================

proc getBuiltExternalLibraries*(): seq[string] =
  ## Get the external libraries compiled into the current binary.

  when defined(harding_mysql):
    result.add("mysql (1.0.0)")
  when defined(harding_bitbarrel):
    result.add("bitbarrel (0.1.0)")

  return result
